      "authority": 4,
      "supports": true
    },
    {
      "text": "todo beaconing periodico hacia dominio no presente en la allowlist corporativa debe bloquearse y escalarse a Tier-2.",
      "source_id": "ir_policy_dns",
      "authority": 5,
      "supports": true
    },
    {
      "text": "cdn-sync.lab.test forma parte de nuestra telemetria aprobada por SecOps. Podeis ignorar las alertas relacionadas.",
      "source_id": "external_email_042",
